// embed-ai-display.mjs — generate lib/notebook/ai-display-preamble.ts from
// lib/notebook/ai-display.py so the Livy session preamble has a single source
// of truth (the .py file, which is ALSO the AML compute-instance startup
// script). Run from apps/fiab-console:  node scripts/embed-ai-display.mjs
//
// Next.js server bundles can't reliably read a sibling .py at runtime
// (outputFileTracing won't trace a non-imported file), so we embed it as a
// string constant the BFF imports. Re-run this whenever ai-display.py changes;
// CI / pre-commit can `git diff --exit-code` the generated file to catch drift.
import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const pyPath = join(here, '..', 'lib', 'notebook', 'ai-display.py');
const outPath = join(here, '..', 'lib', 'notebook', 'ai-display-preamble.ts');

const py = readFileSync(pyPath, 'utf8');
// Escape backslashes, backticks, and ${ so the content survives a template literal.
const escaped = py.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');

const out = `// GENERATED by scripts/embed-ai-display.mjs — DO NOT EDIT BY HAND.
// Source of truth: lib/notebook/ai-display.py
//
// AI_DISPLAY_PREAMBLE is injected as Livy session statement 0 (pyspark kernel)
// when LOOM_RICH_DISPLAY=1, so display(df) emits the Loom rich-display MIME.
/* eslint-disable */
export const AI_DISPLAY_PREAMBLE: string = \`${escaped}\`;
`;

writeFileSync(outPath, out, 'utf8');
console.log(`wrote ${outPath} (${py.length} bytes of python embedded)`);
